class Solution:
    def asteroidCollision(self, asteroids: List[int]) -> List[int]:
        st = []
        for x in asteroids:
            while st and st[-1] > 0 and x < 0:
                if st[-1] < -x: st.pop(); continue
                if st[-1] == -x: st.pop()
                x = 0
                break
            if x: st.append(x)
        return st

