class Solution {
public:
    vector<int> asteroidCollision(vector<int>& a) {
        vector<int> st;
        for (int x : a) {
            bool alive = true;
            while (alive && !st.empty() && st.back() > 0 && x < 0) {
                if (st.back() < -x) { st.pop_back(); continue; }
                if (st.back() == -x) st.pop_back();
                alive = false;
            }
            if (alive) st.push_back(x);
        }
        return st;
    }
};

