int* asteroidCollision(int* asteroids, int n, int* retSize) {
    int* st = malloc(n * 4); int top = 0;
    for (int i = 0; i < n; i++) {
        int x = asteroids[i], alive = 1;
        while (alive && top && st[top-1] > 0 && x < 0) {
            if (st[top-1] < -x) { top--; continue; }
            if (st[top-1] == -x) top--;
            alive = 0;
        }
        if (alive) st[top++] = x;
    }
    *retSize = top; return st;
}
